<script setup lang="ts">import{ref}from'vue';import{Check,Dumbbell}from'lucide-vue-next';defineProps<{title:string;content:string}>();const emit=defineEmits<{complete:[]}>();const done=ref(false);function toggle(){done.value=!done.value;if(done.value)emit('complete')}</script>
<template><section class="engine-card active-practice"><header><span><Dumbbell/></span><div><small>Active recall</small><h3>{{title}}</h3></div></header><p>{{content}}</p><button :class="{done}" @click="toggle"><Check/>{{done?'Практика выполнена':'Отметить после выполнения'}}</button></section></template>